class Solution:
    def evenOddBit(self, n: int) -> List[int]:
        even, odd = 0, 0
        bin_n = bin(n)[2:]
        for i, bit in enumerate(bin_n):
            if bit == '1':
                if i % 2 == 0:
                    even += 1
                else:
                    odd += 1
        return [even, odd]
